// Parse PV inverter Modbus data
// Typical registers for solar inverters:
// 40001-40002: AC Power (W)
// 40003-40004: AC Voltage L1 (V)
// 40005-40006: AC Current L1 (A)
// 40007-40008: AC Frequency (Hz)
// 40009-40010: DC Power (W)
// 40011-40012: DC Voltage (V)
// 40013-40014: DC Current (A)
// 40015: Inverter Status
// 40016: Temperature (°C)
// 40017-40018: Daily Energy (kWh)
// 40019-40020: Total Energy (kWh)

const buffer = msg.payload.buffer;
const data = msg.payload.data;

if (buffer && buffer.length >= 40) {
    const parsed = {
        timestamp: new Date().toISOString(),
        device: 'pv_inverter',
        ac_power: buffer.readUInt32BE(0) / 10, // W
        ac_voltage_l1: buffer.readUInt32BE(4) / 10, // V
        ac_current_l1: buffer.readUInt32BE(8) / 100, // A
        ac_frequency: buffer.readUInt32BE(12) / 100, // Hz
        dc_power: buffer.readUInt32BE(16) / 10, // W
        dc_voltage: buffer.readUInt32BE(20) / 10, // V
        dc_current: buffer.readUInt32BE(24) / 100, // A
        status: buffer.readUInt16BE(28), // Status code
        temperature: buffer.readInt16BE(30) / 10, // °C
        daily_energy: buffer.readUInt32BE(32) / 100, // kWh
        total_energy: buffer.readUInt32BE(36) / 100, // kWh
        efficiency: 0 // Will be calculated
    };

    // Calculate efficiency
    if (parsed.dc_power > 0) {
        parsed.efficiency = (parsed.ac_power / parsed.dc_power) * 100;
    }

    // Store in global context for use by other flows
    global.set('pv_data', parsed);

    msg.payload = parsed;
    msg.topic = 'pv/data';

    return msg;
} else {
    node.error('Invalid data length from PV inverter');
    return null;
}

// Parse genset controller Modbus data
// Typical registers for genset controllers:
// 40001-40002: AC Power (W)
// 40003: AC Voltage L1 (V)
// 40004: AC Voltage L2 (V)
// 40005: AC Voltage L3 (V)
// 40006: AC Current L1 (A)
// 40007: AC Current L2 (A)
// 40008: AC Current L3 (A)
// 40009: Frequency (Hz)
// 40010: Engine RPM
// 40011: Engine Temperature (°C)
// 40012: Oil Pressure (bar)
// 40013: Fuel Level (%)
// 40014: Run Hours
// 40015: Status/Alarms

const buffer = msg.payload.buffer;
const data = msg.payload.data;

if (buffer && buffer.length >= 30) {
    const parsed = {
        timestamp: new Date().toISOString(),
        device: 'genset',
        ac_power: buffer.readUInt32BE(0) / 10, // W
        ac_voltage_l1: buffer.readUInt16BE(4) / 10, // V
        ac_voltage_l2: buffer.readUInt16BE(6) / 10, // V
        ac_voltage_l3: buffer.readUInt16BE(8) / 10, // V
        ac_current_l1: buffer.readUInt16BE(10) / 100, // A
        ac_current_l2: buffer.readUInt16BE(12) / 100, // A
        ac_current_l3: buffer.readUInt16BE(14) / 100, // A
        frequency: buffer.readUInt16BE(16) / 100, // Hz
        engine_rpm: buffer.readUInt16BE(18), // RPM
        engine_temp: buffer.readInt16BE(20) / 10, // °C
        oil_pressure: buffer.readUInt16BE(22) / 100, // bar
        fuel_level: buffer.readUInt16BE(24) / 10, // %
        run_hours: buffer.readUInt16BE(26), // hours
        status: buffer.readUInt16BE(28), // Status/Alarms
        running: false
    };

    // Determine if genset is running
    parsed.running = parsed.engine_rpm > 500 && parsed.ac_power > 100;

    // Store in global context for use by other flows
    global.set('genset_data', parsed);

    msg.payload = parsed;
    msg.topic = 'genset/data';

    return msg;
} else {
    node.error('Invalid data length from genset controller');
    return null;
}

