    alerts.push({
        type: 'warning',
        device: 'power_meter',
        message: `Grid voltage abnormal: ${avgVoltage.toFixed(1)}V`,
        timestamp: data.timestamp
    });
}

// Check for frequency issues
if (data.frequency < 49.5 || data.frequency > 50.5) {
    alerts.push({
        type: 'warning',
        device: 'power_meter',
        message: `Grid frequency abnormal: ${data.frequency}Hz`,
        timestamp: data.timestamp
    });
}

// Check for excessive export
if (data.exporting && Math.abs(data.total_active_power) > 10000) {
    alerts.push({
        type: 'info',
        device: 'power_meter',
        message: `High export power: ${Math.abs(data.total_active_power)}W`,
        timestamp: data.timestamp
    });
