    alerts.push({
        type: 'info',
        device: 'power_meter',
        message: `Poor power factor: ${data.power_factor}`,
        timestamp: data.timestamp
    });
}

if (alerts.length > 0) {
    msg.payload = alerts;
    return msg;
}

